#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <algorithm>

using namespace std;

int main() {
    string filename, wordToFind;
    int count = 0;

    // Get filename and word to search from the user
    cout << "Enter the filename: ";
    cin >> filename;

    cout << "Enter the word to count: ";
    cin >> wordToFind;

    // Open the file for reading
    ifstream file(filename);

    if (!file.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return 1;
    }

    string line;
    while (getline(file, line)) {
        // Convert the line to lowercase for case-insensitive search
        transform(line.begin(), line.end(), line.begin(), ::tolower);

        // Use stringstream to easily extract words
        stringstream ss(line);
        string word;
        while (ss >> word) {
            // Convert extracted word to lowercase for comparison
            transform(word.begin(), word.end(), word.begin(), ::tolower);

            if (word == wordToFind) {
                count++;
            }
        }
    }

    file.close();

    cout << "The word '" << wordToFind << "' appears " << count << " times in the file." << endl;

    return 0;
}
